#include<bits/stdc++.h>
using namespace std;
int main(){
    string s;
    string ans;
    int maxx=0;
    while(cin>>s){
        if(maxx<s.length()){
            if(s[s.length()-1]=='.'&&s.length()-1>maxx){
                for(int i=0;i<s.length()-1;i++){
                    cout<<s[i];
                }
                return 0;
            }else if(s[s.length()-1]!='.'){
                ans=s;
                maxx=s.length();
            }
        }
    }
    cout<<ans;
}
